package com.xoxo.pos.accounts;
import com.fasterxml.jackson.annotation.JsonIgnore;import com.xoxo.pos.products.Product;import jakarta.persistence.*;import java.math.BigDecimal;
@Entity @Table(name="account_items") public class AccountItem{
@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;@JsonIgnore @ManyToOne private Account account;@ManyToOne private Product product;private Integer quantity;@Column(precision=10,scale=2) private BigDecimal unitPrice;@Column(precision=10,scale=2) private BigDecimal unitCost=BigDecimal.ZERO;@Column(precision=10,scale=2) private BigDecimal subtotal;@Column(precision=10,scale=2) private BigDecimal costSubtotal=BigDecimal.ZERO;@Column(precision=10,scale=2) private BigDecimal grossProfit=BigDecimal.ZERO;
public Long getId(){return id;}public Account getAccount(){return account;}public Product getProduct(){return product;}public Integer getQuantity(){return quantity;}public BigDecimal getUnitPrice(){return unitPrice;}public BigDecimal getUnitCost(){return unitCost;}public BigDecimal getSubtotal(){return subtotal;}public BigDecimal getCostSubtotal(){return costSubtotal;}public BigDecimal getGrossProfit(){return grossProfit;}
public void setId(Long id){this.id=id;}public void setAccount(Account account){this.account=account;}public void setProduct(Product product){this.product=product;}public void setQuantity(Integer quantity){this.quantity=quantity;}public void setUnitPrice(BigDecimal unitPrice){this.unitPrice=unitPrice;}public void setUnitCost(BigDecimal unitCost){this.unitCost=unitCost;}public void setSubtotal(BigDecimal subtotal){this.subtotal=subtotal;}public void setCostSubtotal(BigDecimal costSubtotal){this.costSubtotal=costSubtotal;}public void setGrossProfit(BigDecimal grossProfit){this.grossProfit=grossProfit;}}
